mapper.select:
SELECT a.ID, a.ALLOCATE_CODE, a.TITLE, a.TO_COMPANY_ID, a.TO_ORG_ID, a.STATUS, a.ALLOCATE_TIME, a.APPLY_USER, a.APPLY_REASON, a.EXECUTE_USER, a.ALLOCATE_FULFIL_TIME, a.DEL_FLAG, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_BY_NAME, a.UPDATE_TIME, a.FLOW_ID, d.DEPT_NAME as TO_COMPANY_NAME, u.DEPT_NAME as TO_ORG_NAME, su.USER_NAME as APPLY_USER_NAME, CASE a.STATUS WHEN 1 THEN '审批中' WHEN 2 THEN '审批成功' WHEN 3 THEN '审批未通过' ELSE '未知' END as STATUS_NAME, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_M_EQUIP_ALLOCATE a LEFT JOIN SYS_DEPT d ON a.TO_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON a.TO_ORG_ID = u.ID LEFT JOIN SYS_USER su ON a.APPLY_USER = su.ID AND su.STATUS != 0 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = a.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
a.DEL_FLAG = 0
AND a.ALLOCATE_CODE LIKE #{allocateCodePattern}
AND a.TITLE LIKE #{titlePattern}
AND a.TO_COMPANY_ID = #{toCompanyId}
AND a.TO_ORG_ID = #{toOrgId}
AND a.STATUS = #{status}
ORDER BY a.CREATE_TIME DESC

SELECT e.ID as equipId, e.EQUIP_CODE as equipCode, e.EQUIP_NAME as equipName, e.MODEL_NUMBER as modelNumber, ebc.TYPE_NAME as equipBigCategoryName, emc.TYPE_NAME as equipMiddleCategoryName, esc.TYPE_NAME as equipSmallCategoryName, -- d.DEPT_NAME as useCompanyName, (SELECT ID FROM SYS_DEPT WHERE ID = u.PARENT_ID) as useCompanyId, (SELECT DEPT_NAME FROM SYS_DEPT WHERE ID = u.PARENT_ID) as useCompanyName, u.ID as useOrgId, u.DEPT_NAME as useOrgName, e.EQUIP_STATE as equipState, e.EQUIP_STATE_NAME as equipStateName, efi.EQUIP_ASSETS_CODE as equipAssetsCode, efi.DEPRECIATION_LIMIT as depreciationLimit, efi.ALREADY_LIMIT as alreadyLimit, efi.NET_VALUE as netValue, efi.PRICE as price, esi.EQUIP_BUY_DATE as equipBuyDate FROM E_M_EQPT_INFO e LEFT JOIN E_M_EQPT_TYPE ebc ON e.EQUIP_BIG_CATEGORY_ID = ebc.ID LEFT JOIN E_M_EQPT_TYPE emc ON e.EQUIP_MIDDLE_CATEGORY_ID = emc.ID LEFT JOIN E_M_EQPT_TYPE esc ON e.EQUIP_SMALL_CATEGORY_ID = esc.ID LEFT JOIN SYS_DEPT d ON e.USE_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON e.USE_ORG_ID = u.ID LEFT JOIN E_M_EQPT_FINANCE efi ON e.ID = efi.EQUIP_ID AND efi.DEL_FLAG = 0 LEFT JOIN E_M_EQPT_SUPPLY esi ON e.ID = esi.EQUIP_ID AND esi.DEL_FLAG = 0
e.DEL_FLAG = 0 AND e.EQUIP_STATE NOT IN ('03', '04')
AND e.EQUIP_BIG_CATEGORY_ID = #{equipBigCategoryId}
AND e.EQUIP_MIDDLE_CATEGORY_ID = #{equipMiddleCategoryId}
AND e.EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND e.EQUIP_CODE LIKE #{equipCodePattern}
AND u.PARENT_ID = #{useCompanyId}
AND e.USE_ORG_ID = #{useOrgId}
ORDER BY e.CREATE_TIME DESC

