mapper.update:
UPDATE E_M_EQUIP_ALLOCATE
TITLE = #{title}, TO_COMPANY_ID = #{toCompanyId}, TO_ORG_ID = #{toOrgId}, STATUS = #{status}, ALLOCATE_TIME = #{allocateTime}, APPLY_REASON = #{applyReason}, EXECUTE_USER = #{executeUser}, ALLOCATE_FULFIL_TIME = #{allocateFulfilTime}, FLOW_ID = #{flowId}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime}
WHERE ID = #{id}

UPDATE E_M_EQUIP_ALLOCATE
STATUS = #{status}, EXECUTE_USER = #{executeUser}, ALLOCATE_FULFIL_TIME = #{allocateFulfilTime}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime},
WHERE ID = #{id}

mapper.select:
SELECT a.ID, a.ALLOCATE_CODE, a.TITLE, a.TO_COMPANY_ID, a.TO_ORG_ID, a.STATUS, a.ALLOCATE_TIME, a.APPLY_USER, a.APPLY_REASON, a.EXECUTE_USER, a.ALLOCATE_FULFIL_TIME, a.DEL_FLAG, a.CREATE_BY, a.CREATE_BY_NAME, a.CREATE_TIME, a.UPDATE_BY, a.UPDATE_BY_NAME, a.UPDATE_TIME, a.FLOW_ID, d.DEPT_NAME as TO_COMPANY_NAME, u.DEPT_NAME as TO_ORG_NAME, su.USER_NAME as APPLY_USER_NAME, CASE a.STATUS WHEN 1 THEN '审批中' WHEN 2 THEN '审批成功' WHEN 3 THEN '审批未通过' ELSE '未知' END as STATUS_NAME FROM E_M_EQUIP_ALLOCATE a LEFT JOIN SYS_DEPT d ON a.TO_COMPANY_ID = d.ID LEFT JOIN SYS_DEPT u ON a.TO_ORG_ID = u.ID LEFT JOIN SYS_USER su ON a.APPLY_USER = su.ID AND su.STATUS != 0
a.DEL_FLAG = 0
AND a.ALLOCATE_CODE LIKE #{allocateCodePattern}
AND a.TITLE LIKE #{titlePattern}
AND a.TO_COMPANY_ID = #{toCompanyId}
AND a.TO_ORG_ID = #{toOrgId}
AND a.STATUS = #{status}
ORDER BY a.CREATE_TIME DESC
